CustomField.formula:
IF(ISBLANK(Score_Primary_Source_of_Wealth__c ), "",
IF(Score_Primary_Source_of_Wealth__c >= 4, IMAGE("/img/samples/flag_red.gif", "high") + " High",
IF(Score_Primary_Source_of_Wealth__c > 2, IMAGE("/img/samples/flag_yellow.gif", "medium") + " Medium",
IF(Score_Primary_Source_of_Wealth__c >= 0, IMAGE("/img/samples/flag_green.gif", "low") + " Low", "")
)
)
)
